INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Sumo_Deadlift_with_Chains','Sumo Deadlift with Chains','isquiotibiales',ARRAY['abductores','aductores','antebrazos','glúteos','espalda baja','espalda media','cuádriceps','trapecios'],'barra','powerlifting',ARRAY['You can attach the chains to the sleeves of the bar, or just drape the middle over the bar so there is a greater weight increase as you lift. Attempt to keep the ends of the chains away from the plates so you don''''t hit them when you lower the weight.','Begin with a bar loaded on the ground. Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip. Relax the shoulders, which in effect lengthens your arms.','Take a breath, and then lower your hips, looking forward with your head with your chest up. Drive through the floor, spreading your feet apart, with your weight on the back half of your feet. Extend through the hips and knees.','As the bar passes through the knees, lean back and drive the hips into the bar, pulling your shoulder blades together.','Return the weight to the ground by bending at the hips and controlling the weight on the way down.'],'You can attach the chains to the sleeves of the bar, or just drape the middle over the bar so there is a greater weight increase as you lift. Attempt to keep the ends of the chains away from the plates so you don''t hit them when you lower the weight. Begin with a bar loaded on the ground. Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip. Relax the shoulders, which in effect lengthens your arms. Take a breath, and then lower your hips, looking forward with your head with your chest up. Drive through the floor, spreading your feet apart, with your weight on the back half of your feet. Extend through the hips and knees. As the bar passes through the knees, lean back and drive the hips into the bar, pulling your shoulder blades together. Return the weight to the ground by bending at the hips and controlling the weight on the way down.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Sumo_Deadlift_with_Chains/0.jpg','exercisedb',true),('Superman','Superman','espalda baja',ARRAY['glúteos','isquiotibiales'],'peso corporal','stretching',ARRAY['To begin, lie straight and face down on the floor or exercise mat. Your arms should be fully extended in front of you. This is the starting position.','Simultaneously raise your arms, legs, and chest off of the floor and hold this contraction for 2 seconds. Tip: Squeeze your lower back to get the best results from this exercise. Remember to exhale during this movement. Note: When holding the contracted position, you should look like superman when he is flying.','Slowly begin to lower your arms, legs and chest back down to the starting position while inhaling.','Repeat for the recommended amount of repetitions prescribed in your program.'],'To begin, lie straight and face down on the floor or exercise mat. Your arms should be fully extended in front of you. This is the starting position. Simultaneously raise your arms, legs, and chest off of the floor and hold this contraction for 2 seconds. Tip: Squeeze your lower back to get the best results from this exercise. Remember to exhale during this movement. Note: When holding the contracted position, you should look like superman when he is flying. Slowly begin to lower your arms, legs and chest back down to the starting position while inhaling. Repeat for the recommended amount of repetitions prescribed in your program.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Superman/0.jpg','exercisedb',true),('Supine_Chest_Throw','Supine Chest Throw','tríceps',ARRAY['pecho','hombros'],'balón medicinal','plyometrics',ARRAY['This drill is great for chest passes when you lack a partner or a wall of sufficient strength. Lay on the ground on your back with your knees bent.','Begin with the ball on your chest, held with both hands on the bottom.','Explode up, extending through the elbow to throw the ball directly above you as high as possible.','Catch the ball with both hands as it comes down.'],'This drill is great for chest passes when you lack a partner or a wall of sufficient strength. Lay on the ground on your back with your knees bent. Begin with the ball on your chest, held with both hands on the bottom. Explode up, extending through the elbow to throw the ball directly above you as high as possible. Catch the ball with both hands as it comes down.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Supine_Chest_Throw/0.jpg','exercisedb',true),('Supine_One-Arm_Overhead_Throw','Supine One-Arm Overhead Throw','abdominales',ARRAY['pecho','dorsales','hombros'],'balón medicinal','plyometrics',ARRAY['Lay on the ground on your back with your knees bent. Hold the ball with one hand, extending the arm fully behind your head. This will be your starting position.','Initiate the movement at the shoulder, throwing the ball directly forward of you as you sit up, attempting to go for maximum distance.','The ball can be thrown to a partner or bounced off of a wall.'],'Lay on the ground on your back with your knees bent. Hold the ball with one hand, extending the arm fully behind your head. This will be your starting position. Initiate the movement at the shoulder, throwing the ball directly forward of you as you sit up, attempting to go for maximum distance. The ball can be thrown to a partner or bounced off of a wall.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Supine_One-Arm_Overhead_Throw/0.jpg','exercisedb',true),('Supine_Two-Arm_Overhead_Throw','Supine Two-Arm Overhead Throw','abdominales',ARRAY['pecho','dorsales','hombros'],'balón medicinal','plyometrics',ARRAY['Lay on the ground on your back with your knees bent.','Hold the ball with both hands, extending the arms fully behind your head. This will be your starting position.','Initiate the movement at the shoulder, throwing the ball directly forward of you as you sit up, attempting to go for maximum distance.','The ball can be thrown to a partner or bounced off of a wall.'],'Lay on the ground on your back with your knees bent. Hold the ball with both hands, extending the arms fully behind your head. This will be your starting position. Initiate the movement at the shoulder, throwing the ball directly forward of you as you sit up, attempting to go for maximum distance. The ball can be thrown to a partner or bounced off of a wall.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Supine_Two-Arm_Overhead_Throw/0.jpg','exercisedb',true),('Suspended_Fallout','Suspended Fallout','abdominales',ARRAY['pecho','espalda baja','hombros'],'otro','strength',ARRAY['Adjust the straps so the handles are at an appropriate height, below waist level.','Begin standing and grasping the handles. Lean into the straps, moving to an incline push-up position. This will be your starting position.','Keeping your arms straight, lean further into the suspension straps, bringing your body closer to the ground, allowing your shoulders to extend, raising your arms up and over your head.','Maintain a neutral spine and keep the rest of your body straight, your shoulders being the only joints allowed to move.','Pause during the peak contraction, and then return to the starting position.'],'Adjust the straps so the handles are at an appropriate height, below waist level. Begin standing and grasping the handles. Lean into the straps, moving to an incline push-up position. This will be your starting position. Keeping your arms straight, lean further into the suspension straps, bringing your body closer to the ground, allowing your shoulders to extend, raising your arms up and over your head. Maintain a neutral spine and keep the rest of your body straight, your shoulders being the only joints allowed to move. Pause during the peak contraction, and then return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Suspended_Fallout/0.jpg','exercisedb',true),('Suspended_Push-Up','Suspended Push-Up','pecho',ARRAY['hombros','tríceps'],'otro','strength',ARRAY['Anchor your suspension straps securely to the top of a rack or other object.','Leaning into the straps, take a handle in each hand and move into a push-up plank position. You should be as close to parallel to the ground as you can manage with your arms fully extended, maintaining good posture.','Maintaining a straight, rigid torso, descend slowly by allowing the elbows to flex.','Continue until your elbows break 90 degrees, pausing before you extend to return to the starting position.'],'Anchor your suspension straps securely to the top of a rack or other object. Leaning into the straps, take a handle in each hand and move into a push-up plank position. You should be as close to parallel to the ground as you can manage with your arms fully extended, maintaining good posture. Maintaining a straight, rigid torso, descend slowly by allowing the elbows to flex. Continue until your elbows break 90 degrees, pausing before you extend to return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Suspended_Push-Up/0.jpg','exercisedb',true),('Suspended_Reverse_Crunch','Suspended Reverse Crunch','abdominales',ARRAY[]::text[],'otro','strength',ARRAY['Secure a set of suspension straps with the handles hanging about a foot off of the ground. Move yourself into a pushup plank position facing away from the rack.','Place your feet into the handles. You should maintain a straight posture, not allowing the hips to sag. This will be your starting position.','Begin the movement by flexing the knees and hips, drawing the knees to your torso. As you do so, anteriorly tilt your pelvis, allowing your spine to flex.','At the top of the controlled motion, return to the starting position.'],'Secure a set of suspension straps with the handles hanging about a foot off of the ground. Move yourself into a pushup plank position facing away from the rack. Place your feet into the handles. You should maintain a straight posture, not allowing the hips to sag. This will be your starting position. Begin the movement by flexing the knees and hips, drawing the knees to your torso. As you do so, anteriorly tilt your pelvis, allowing your spine to flex. At the top of the controlled motion, return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Suspended_Reverse_Crunch/0.jpg','exercisedb',true),('Suspended_Row','Suspended Row','espalda media',ARRAY['bíceps','dorsales'],'otro','strength',ARRAY['Suspend your straps at around chest height. Take a handle in each hand and lean back. Keep your body erect and your head and chest up. Your arms should be fully extended. This will be your starting position.','Begin by flexing the elbow to initiate the movement. Protract your shoulder blades as you do so.','At the completion of the motion pause, and then return to the starting position.'],'Suspend your straps at around chest height. Take a handle in each hand and lean back. Keep your body erect and your head and chest up. Your arms should be fully extended. This will be your starting position. Begin by flexing the elbow to initiate the movement. Protract your shoulder blades as you do so. At the completion of the motion pause, and then return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Suspended_Row/0.jpg','exercisedb',true),('Suspended_Split_Squat','Suspended Split Squat','cuádriceps',ARRAY['abductores','aductores','pantorrillas','glúteos','isquiotibiales'],'otro','strength',ARRAY['Suspend your straps so the handles are 18-30 inches from the floor.','Facing away from the setup, place your rear foot into the handle behind you. Keep your head looking forward and your chest up, with your knee slightly bent. This will be your starting position.','Descend by flexing the knee and hips, lowering yourself to the ground. Keep your weight on the heel of your foot and maintain your posture throughout the exercise.','At the bottom of the movement, reverse the motion, extending through the hip and knee to return to the starting position.'],'Suspend your straps so the handles are 18-30 inches from the floor. Facing away from the setup, place your rear foot into the handle behind you. Keep your head looking forward and your chest up, with your knee slightly bent. This will be your starting position. Descend by flexing the knee and hips, lowering yourself to the ground. Keep your weight on the heel of your foot and maintain your posture throughout the exercise. At the bottom of the movement, reverse the motion, extending through the hip and knee to return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Suspended_Split_Squat/0.jpg','exercisedb',true);